using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

public static class TestHelper
{
    public static SchoolContext CreateContext(string dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    public static SchoolContext CreateSeededContext(string dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var context = CreateContext(dbName);
        SeedData(context);
        return context;
    }

    public static void SeedData(SchoolContext context)
    {
        var instructor1 = new Instructor
        {
            ID = 1,
            LastName = "Smith",
            FirstMidName = "John",
            HireDate = new DateTime(2010, 1, 15),
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment { InstructorID = 1, Location = "Room 101" }
        };
        var instructor2 = new Instructor
        {
            ID = 2,
            LastName = "Jones",
            FirstMidName = "Jane",
            HireDate = new DateTime(2012, 3, 20),
            CourseAssignments = new List<CourseAssignment>()
        };

        context.Instructors.AddRange(instructor1, instructor2);

        var dept1 = new Department
        {
            DepartmentID = 1,
            Name = "Computer Science",
            Budget = 100000,
            StartDate = new DateTime(2000, 9, 1),
            InstructorID = 1
        };
        var dept2 = new Department
        {
            DepartmentID = 2,
            Name = "Mathematics",
            Budget = 80000,
            StartDate = new DateTime(2001, 9, 1),
            InstructorID = 2
        };

        context.Departments.AddRange(dept1, dept2);

        var course1 = new Course
        {
            CourseID = 1001,
            Title = "Intro to CS",
            Credits = 3,
            DepartmentID = 1,
            Enrollments = new List<Enrollment>(),
            CourseAssignments = new List<CourseAssignment>()
        };
        var course2 = new Course
        {
            CourseID = 1002,
            Title = "Calculus",
            Credits = 4,
            DepartmentID = 2,
            Enrollments = new List<Enrollment>(),
            CourseAssignments = new List<CourseAssignment>()
        };

        context.Courses.AddRange(course1, course2);

        var student1 = new Student
        {
            ID = 10,
            LastName = "Doe",
            FirstMidName = "Alice",
            EnrollmentDate = new DateTime(2020, 9, 1),
            Enrollments = new List<Enrollment>()
        };
        var student2 = new Student
        {
            ID = 11,
            LastName = "Brown",
            FirstMidName = "Bob",
            EnrollmentDate = new DateTime(2021, 1, 15),
            Enrollments = new List<Enrollment>()
        };
        var student3 = new Student
        {
            ID = 12,
            LastName = "Adams",
            FirstMidName = "Charlie",
            EnrollmentDate = new DateTime(2020, 9, 1),
            Enrollments = new List<Enrollment>()
        };

        context.Students.AddRange(student1, student2, student3);

        var enrollment1 = new Enrollment { EnrollmentID = 1, CourseID = 1001, StudentID = 10, Grade = Grade.A };
        var enrollment2 = new Enrollment { EnrollmentID = 2, CourseID = 1002, StudentID = 10, Grade = Grade.B };
        var enrollment3 = new Enrollment { EnrollmentID = 3, CourseID = 1001, StudentID = 11, Grade = Grade.C };

        context.Enrollments.AddRange(enrollment1, enrollment2, enrollment3);

        var ca1 = new CourseAssignment { InstructorID = 1, CourseID = 1001 };
        var ca2 = new CourseAssignment { InstructorID = 2, CourseID = 1002 };
        context.CourseAssignments.AddRange(ca1, ca2);

        context.SaveChanges();
    }
}

