using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests
{
    [Fact]
    public void Index_DefaultSort_ReturnsViewWithStudentsOrderedByLastName()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.Index(null, null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(3, model.Count);
        Assert.Equal("Adams", model[0].LastName);
        Assert.Equal("Brown", model[1].LastName);
        Assert.Equal("Doe", model[2].LastName);
    }

    [Fact]
    public void Index_NameDescSort_ReturnsStudentsInDescendingOrder()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.Index("name_desc", null, null, null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal("Doe", model[0].LastName);
        Assert.Equal("Brown", model[1].LastName);
        Assert.Equal("Adams", model[2].LastName);
    }

    [Fact]
    public void Index_DateSort_ReturnsStudentsOrderedByEnrollmentDate()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.Index("Date", null, null, null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        // 2020-09-01 comes before 2021-01-15
        Assert.True(model[0].EnrollmentDate <= model[1].EnrollmentDate);
    }

    [Fact]
    public void Index_DateDescSort_ReturnsStudentsInDescendingDateOrder()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.Index("date_desc", null, null, null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.True(model[0].EnrollmentDate >= model[1].EnrollmentDate);
    }

    [Fact]
    public void Index_WithSearchString_FiltersStudents()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.Index(null, null, "Doe", null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
        Assert.Equal("Doe", model[0].LastName);
    }

    [Fact]
    public void Index_WithSearchString_ResetsPageTo1()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.Index(null, null, "Doe", 5) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.Index(null, "Brown", null, null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
        Assert.Equal("Brown", model[0].LastName);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsStudentWithEnrollments()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.Details(10) as ViewResult;

        Assert.NotNull(result);
        var student = Assert.IsType<Student>(result.Model);
        Assert.Equal("Doe", student.LastName);
        Assert.NotNull(student.Enrollments);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithStudentWithTodaysDate()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.Create() as ViewResult;

        Assert.NotNull(result);
        var student = Assert.IsType<Student>(result.Model);
        Assert.Equal(DateTime.Today, student.EnrollmentDate);
    }

    [Fact]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);
        var student = new Student
        {
            LastName = "New",
            FirstMidName = "Student",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        var result = controller.Create(student) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(4, context.Students.Count());
    }

    [Fact]
    public void Create_Post_InvalidEnrollmentDate_ReturnsView()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);
        var student = new Student
        {
            LastName = "Bad",
            FirstMidName = "Date",
            EnrollmentDate = DateTime.MinValue
        };

        var result = controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.False(controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_Post_DateOutOfSqlRange_ReturnsView()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);
        var student = new Student
        {
            LastName = "Range",
            FirstMidName = "Out",
            EnrollmentDate = new DateTime(1000, 1, 1)
        };

        var result = controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.False(controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);
        controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            LastName = "X",
            FirstMidName = "Y",
            EnrollmentDate = new DateTime(2023, 1, 1)
        };

        var result = controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.Equal(3, context.Students.Count()); // not saved
    }

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.Edit((int?)null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Edit_Get_NotFound_ReturnsNotFound()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.Edit(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithStudent()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.Edit(10) as ViewResult;

        Assert.NotNull(result);
        var student = Assert.IsType<Student>(result.Model);
        Assert.Equal("Doe", student.LastName);
    }

    [Fact]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);
        var student = context.Students.Find(10);
        student.LastName = "Updated";
        context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var result = controller.Edit(student) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidDate_ReturnsView()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);
        var student = new Student
        {
            ID = 10,
            LastName = "Doe",
            FirstMidName = "Alice",
            EnrollmentDate = DateTime.MinValue
        };

        var result = controller.Edit(student) as ViewResult;

        Assert.NotNull(result);
        Assert.False(controller.ModelState.IsValid);
    }

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.Delete(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Delete_Get_NotFound_ReturnsNotFound()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.Delete(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithStudent()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.Delete(10) as ViewResult;

        Assert.NotNull(result);
        var student = Assert.IsType<Student>(result.Model);
        Assert.Equal("Doe", student.LastName);
    }

    [Fact]
    public void DeleteConfirmed_RemovesStudentAndRedirects()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.DeleteConfirmed(10) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(2, context.Students.Count());
    }

    [Fact]
    public void Index_SearchByFirstName_FindsStudent()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new StudentsController(context);

        var result = controller.Index(null, null, "Alice", null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
        Assert.Equal("Alice", model[0].FirstMidName);
    }
}

