using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Fact]
    public void Create_ReturnsCorrectPageOfItems()
    {
        var items = Enumerable.Range(1, 25).AsQueryable();

        var page = PaginatedList<int>.Create(items, 1, 10);

        Assert.Equal(10, page.Count);
        Assert.Equal(1, page[0]);
        Assert.Equal(10, page[9]);
    }

    [Fact]
    public void Create_PageIndex_IsCorrect()
    {
        var items = Enumerable.Range(1, 25).AsQueryable();

        var page = PaginatedList<int>.Create(items, 2, 10);

        Assert.Equal(2, page.PageIndex);
    }

    [Fact]
    public void Create_TotalPages_IsCorrect()
    {
        var items = Enumerable.Range(1, 25).AsQueryable();

        var page = PaginatedList<int>.Create(items, 1, 10);

        Assert.Equal(3, page.TotalPages);
    }

    [Fact]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var items = Enumerable.Range(1, 25).AsQueryable();

        var page = PaginatedList<int>.Create(items, 1, 10);

        Assert.False(page.HasPreviousPage);
    }

    [Fact]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        var items = Enumerable.Range(1, 25).AsQueryable();

        var page = PaginatedList<int>.Create(items, 2, 10);

        Assert.True(page.HasPreviousPage);
    }

    [Fact]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        var items = Enumerable.Range(1, 25).AsQueryable();

        var page = PaginatedList<int>.Create(items, 3, 10);

        Assert.False(page.HasNextPage);
    }

    [Fact]
    public void HasNextPage_FirstPage_ReturnsTrue()
    {
        var items = Enumerable.Range(1, 25).AsQueryable();

        var page = PaginatedList<int>.Create(items, 1, 10);

        Assert.True(page.HasNextPage);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var items = Enumerable.Empty<int>().AsQueryable();

        var page = PaginatedList<int>.Create(items, 1, 10);

        Assert.Empty(page);
        Assert.Equal(0, page.TotalPages);
    }

    [Fact]
    public void Create_ExactMultipleOfPageSize_CorrectTotalPages()
    {
        var items = Enumerable.Range(1, 20).AsQueryable();

        var page = PaginatedList<int>.Create(items, 1, 10);

        Assert.Equal(2, page.TotalPages);
    }

    [Fact]
    public void Create_SingleItem_SinglePage()
    {
        var items = new[] { 42 }.AsQueryable();

        var page = PaginatedList<int>.Create(items, 1, 10);

        Assert.Single(page);
        Assert.Equal(1, page.TotalPages);
        Assert.False(page.HasPreviousPage);
        Assert.False(page.HasNextPage);
    }

    [Fact]
    public void Constructor_SetsPropertiesCorrectly()
    {
        var items = new List<string> { "a", "b", "c" };

        var page = new PaginatedList<string>(items, 30, 2, 10);

        Assert.Equal(3, page.Count);
        Assert.Equal(2, page.PageIndex);
        Assert.Equal(3, page.TotalPages);
    }
}

