        using (var context = TestHelper.CreateContext(dbName))
        {
            context.Departments.Add(new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 200000,
                StartDate = new DateTime(2020, 1, 1)
            });
            context.SaveChanges();
        }

        using (var context = TestHelper.CreateContext(dbName))
        {
            var dept = context.Departments.Single();
            Assert.Equal("Engineering", dept.Name);
            Assert.Equal(200000, dept.Budget);
        }
    }

    [Fact]
    public void CanAddAndRetrieveInstructor()
    {
        var dbName = Guid.NewGuid().ToString();
        using (var context = TestHelper.CreateContext(dbName))
        {
            context.Instructors.Add(new Instructor
            {
                LastName = "Prof",
                FirstMidName = "Test",
