using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests
{
    private CoursesController CreateController(SchoolContext context)
    {
        var env = new Mock<IWebHostEnvironment>();
        env.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        env.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        var logger = new Mock<ILogger<CoursesController>>();
        return new CoursesController(context, env.Object, logger.Object);
    }

    [Fact]
    public void Index_ReturnsViewWithAllCourses()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);

        var result = controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);

        var result = controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);

        var result = controller.Details(1001) as ViewResult;

        Assert.NotNull(result);
        var course = Assert.IsType<Course>(result.Model);
        Assert.Equal("Intro to CS", course.Title);
        Assert.NotNull(course.Department);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithDepartmentSelectList()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);

        var result = controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(controller.ViewBag.DepartmentID);
    }

    [Fact]
    public void Create_Post_ValidCourse_RedirectsToIndex()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);
        var course = new Course
        {
            CourseID = 2001,
            Title = "New Course",
            Credits = 3,
            DepartmentID = 1
        };

        var result = controller.Create(course, null) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(3, context.Courses.Count());
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);
        controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 2002, Title = "X", Credits = 1, DepartmentID = 1 };

        var result = controller.Create(course, null) as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(controller.ViewBag.DepartmentID);
    }

    [Fact]
    public void Create_Post_WithInvalidFileExtension_ReturnsViewWithError()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);
        var course = new Course { CourseID = 2003, Title = "Test", Credits = 3, DepartmentID = 1 };

        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("file.exe");
        fileMock.Setup(f => f.Length).Returns(100);

        var result = controller.Create(course, fileMock.Object) as ViewResult;

        Assert.NotNull(result);
        Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_Post_WithOversizedFile_ReturnsViewWithError()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);
        var course = new Course { CourseID = 2004, Title = "Test", Credits = 3, DepartmentID = 1 };

        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("image.jpg");
        fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB

        var result = controller.Create(course, fileMock.Object) as ViewResult;

        Assert.NotNull(result);
        Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_Post_WithValidImage_SavesFileAndRedirects()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);
        var course = new Course { CourseID = 2005, Title = "WithImage", Credits = 3, DepartmentID = 1 };

        var content = new byte[] { 0xFF, 0xD8, 0xFF }; // fake jpg bytes
        var stream = new MemoryStream(content);
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("photo.jpg");
        fileMock.Setup(f => f.Length).Returns(content.Length);
        fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => stream.CopyTo(s));

        var result = controller.Create(course, fileMock.Object) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        var saved = context.Courses.Find(2005);
        Assert.NotNull(saved.TeachingMaterialImagePath);
        Assert.Contains("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
    }

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);

        var result = controller.Edit((int?)null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Edit_Get_NotFound_ReturnsNotFound()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);

        var result = controller.Edit(9999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithCourse()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);

        var result = controller.Edit(1001) as ViewResult;

        Assert.NotNull(result);
        var course = Assert.IsType<Course>(result.Model);
        Assert.Equal("Intro to CS", course.Title);
        Assert.NotNull(controller.ViewBag.DepartmentID);
    }

    [Fact]
    public void Edit_Post_ValidCourse_RedirectsToIndex()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);
        var course = context.Courses.Find(1001);
        course.Title = "Updated";
        context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var result = controller.Edit(course, null) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);
        controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 1001, Title = "X", Credits = 3, DepartmentID = 1 };

        var result = controller.Edit(course, null) as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(controller.ViewBag.DepartmentID);
    }

    [Fact]
    public void Edit_Post_WithInvalidFileExtension_ReturnsViewWithError()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);
        var course = new Course { CourseID = 1001, Title = "Test", Credits = 3, DepartmentID = 1 };

        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("file.txt");
        fileMock.Setup(f => f.Length).Returns(100);

        var result = controller.Edit(course, fileMock.Object) as ViewResult;

        Assert.NotNull(result);
        Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);

        var result = controller.Delete(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithCourse()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);

        var result = controller.Delete(1001) as ViewResult;

        Assert.NotNull(result);
        var course = Assert.IsType<Course>(result.Model);
        Assert.Equal("Intro to CS", course.Title);
    }

    [Fact]
    public void DeleteConfirmed_RemovesCourseAndRedirects()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = CreateController(context);

        var result = controller.DeleteConfirmed(1001) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Single(context.Courses);
    }

    [Fact]
    public void DeleteConfirmed_CourseWithImage_DeletesFileAndRemoves()
    {
        using var context = TestHelper.CreateSeededContext();
        var course = context.Courses.Find(1001);
        course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/nonexistent.jpg";
        context.SaveChanges();
        var controller = CreateController(context);

        var result = controller.DeleteConfirmed(1001) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }
}

