using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class DepartmentsControllerTests
{
    [Fact]
    public void Index_ReturnsViewWithAllDepartments()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new DepartmentsController(context);

        var result = controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new DepartmentsController(context);

        var result = controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Details_NotFound_ReturnsNotFound()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new DepartmentsController(context);

        var result = controller.Details(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithDepartment()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new DepartmentsController(context);

        var result = controller.Details(1) as ViewResult;

        Assert.NotNull(result);
        var dept = Assert.IsType<Department>(result.Model);
        Assert.Equal("Computer Science", dept.Name);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithInstructorSelectList()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new DepartmentsController(context);

        var result = controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(controller.ViewBag.InstructorID);
    }

    [Fact]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new DepartmentsController(context);
        var dept = new Department
        {
            Name = "Physics",
            Budget = 50000,
            StartDate = new DateTime(2023, 9, 1),
            InstructorID = 1
        };

        var result = controller.Create(dept) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(3, context.Departments.Count());
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new DepartmentsController(context);
        controller.ModelState.AddModelError("Name", "Required");
        var dept = new Department { Name = "X", Budget = 0, StartDate = DateTime.Now };

        var result = controller.Create(dept) as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(controller.ViewBag.InstructorID);
    }

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new DepartmentsController(context);

        var result = controller.Edit((int?)null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Edit_Get_NotFound_ReturnsNotFound()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new DepartmentsController(context);

        var result = controller.Edit(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithDepartment()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new DepartmentsController(context);

        var result = controller.Edit(1) as ViewResult;

        Assert.NotNull(result);
        var dept = Assert.IsType<Department>(result.Model);
        Assert.Equal("Computer Science", dept.Name);
        Assert.NotNull(controller.ViewBag.InstructorID);
    }

    [Fact]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new DepartmentsController(context);
        var dept = context.Departments.Find(1);
        dept.Name = "Updated CS";
        context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var result = controller.Edit(dept) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new DepartmentsController(context);
        controller.ModelState.AddModelError("Name", "Required");
        var dept = new Department { DepartmentID = 1, Name = "X", Budget = 100, StartDate = DateTime.Now };

        var result = controller.Edit(dept) as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(controller.ViewBag.InstructorID);
    }

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new DepartmentsController(context);

        var result = controller.Delete(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Delete_Get_NotFound_ReturnsNotFound()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new DepartmentsController(context);

        var result = controller.Delete(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithDepartment()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new DepartmentsController(context);

        var result = controller.Delete(1) as ViewResult;

        Assert.NotNull(result);
        var dept = Assert.IsType<Department>(result.Model);
        Assert.Equal("Computer Science", dept.Name);
    }

    [Fact]
    public void DeleteConfirmed_RemovesDepartmentAndRedirects()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new DepartmentsController(context);

        var result = controller.DeleteConfirmed(1) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Single(context.Departments);
    }
}

