using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests
{
    [Fact]
    public void Index_NoSelection_ReturnsViewWithAllInstructors()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new InstructorsController(context);

        var result = controller.Index(null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.Equal(2, model.Instructors.Count());
    }

    [Fact]
    public void Index_WithInstructorId_PopulatesCourses()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new InstructorsController(context);

        var result = controller.Index(1, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.NotNull(model.Courses);
        Assert.Single(model.Courses);
    }

    [Fact]
    public void Index_WithInstructorAndCourseId_PopulatesEnrollments()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new InstructorsController(context);

        var result = controller.Index(1, 1001) as ViewResult;

        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.NotNull(model.Enrollments);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new InstructorsController(context);

        var result = controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Details_NotFound_ReturnsNotFound()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new InstructorsController(context);

        var result = controller.Details(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new InstructorsController(context);

        var result = controller.Details(1) as ViewResult;

        Assert.NotNull(result);
        var instructor = Assert.IsType<Instructor>(result.Model);
        Assert.Equal("Smith", instructor.LastName);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithInstructor()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new InstructorsController(context);

        var result = controller.Create() as ViewResult;

        Assert.NotNull(result);
        var instructor = Assert.IsType<Instructor>(result.Model);
        Assert.NotNull(instructor.CourseAssignments);
        Assert.NotNull(controller.ViewBag.Courses);
    }

    [Fact]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new InstructorsController(context);
        var instructor = new Instructor
        {
            LastName = "NewInstr",
            FirstMidName = "Test",
            HireDate = new DateTime(2023, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = controller.Create(instructor, null) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(3, context.Instructors.Count());
    }

    [Fact]
    public void Create_Post_WithSelectedCourses_AssignsCourses()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new InstructorsController(context);
        var instructor = new Instructor
        {
            LastName = "WithCourse",
            FirstMidName = "Instructor",
            HireDate = new DateTime(2023, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        var selectedCourses = new[] { "1001", "1002" };

        var result = controller.Create(instructor, selectedCourses) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        var saved = context.Instructors.OrderByDescending(i => i.ID).First();
        Assert.Equal(2, saved.CourseAssignments.Count);
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new InstructorsController(context);
        controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            LastName = "X",
            FirstMidName = "Y",
            HireDate = DateTime.Now,
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = controller.Create(instructor, null) as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(controller.ViewBag.Courses);
    }

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new InstructorsController(context);

        var result = controller.Edit((int?)null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithInstructor()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new InstructorsController(context);

        var result = controller.Edit(1) as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(controller.ViewBag.Courses);
    }

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new InstructorsController(context);

        var result = controller.Delete(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Delete_Get_NotFound_ReturnsNotFound()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new InstructorsController(context);

        var result = controller.Delete(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithInstructor()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new InstructorsController(context);

        var result = controller.Delete(1) as ViewResult;

        Assert.NotNull(result);
        var instructor = Assert.IsType<Instructor>(result.Model);
        Assert.Equal("Smith", instructor.LastName);
    }

    [Fact]
    public void DeleteConfirmed_RemovesInstructorAndRedirects()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new InstructorsController(context);

        var result = controller.DeleteConfirmed(1) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Single(context.Instructors);
    }

    [Fact]
    public void DeleteConfirmed_InstructorWithDepartment_NullsDepartmentAdministrator()
    {
        using var context = TestHelper.CreateSeededContext();
        var controller = new InstructorsController(context);

        controller.DeleteConfirmed(1);

        var dept = context.Departments.Find(1);
        Assert.Null(dept.InstructorID);
    }
}

