using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests
{
    [Fact]
    public void SendNotification_EnqueuesNotification()
    {
        using var service = new NotificationService();

        service.SendNotification("Student", "1", "Alice Doe", EntityOperation.CREATE, "Admin");

        var notification = service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Contains("Alice Doe", notification.Message);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesEntityId()
    {
        using var service = new NotificationService();

        service.SendNotification("Course", "42", EntityOperation.UPDATE);

        var notification = service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("ID: 42", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        using var service = new NotificationService();

        service.SendNotification("Department", "5", "Physics", EntityOperation.DELETE);

        var notification = service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        using var service = new NotificationService();

        // Drain any existing items from the shared queue
        while (service.ReceiveNotification() != null) { }

        var result = service.ReceiveNotification();

        Assert.Null(result);
    }

    [Fact]
    public void SendNotification_CreateOperation_GeneratesCorrectMessage()
    {
        using var service = new NotificationService();

        service.SendNotification("Student", "1", "John Smith", EntityOperation.CREATE, "User");

        var notification = service.ReceiveNotification();
        Assert.Contains("New", notification.Message);
        Assert.Contains("has been created", notification.Message);
    }

    [Fact]
    public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
    {
        using var service = new NotificationService();

        service.SendNotification("Course", "101", "Calculus", EntityOperation.UPDATE, "User");

        var notification = service.ReceiveNotification();
        Assert.Contains("has been updated", notification.Message);
    }

    [Fact]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        using var service = new NotificationService();

        service.SendNotification("Instructor", "5", "Jane Doe", EntityOperation.DELETE, "User");

        var notification = service.ReceiveNotification();
        Assert.Contains("has been deleted", notification.Message);
    }

    [Fact]
    public void SendNotification_SetsCreatedAt()
    {
        using var service = new NotificationService();
        var before = DateTime.Now;

        service.SendNotification("Student", "1", "Name", EntityOperation.CREATE, "User");

        var notification = service.ReceiveNotification();
        Assert.True(notification.CreatedAt >= before);
        Assert.True(notification.CreatedAt <= DateTime.Now);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        using var service = new NotificationService();

        var exception = Record.Exception(() => service.MarkAsRead(999));

        Assert.Null(exception);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();

        var exception = Record.Exception(() => service.Dispose());

        Assert.Null(exception);
    }

    [Fact]
    public void SendNotification_MultipleMessages_MaintainsOrder()
    {
        using var service = new NotificationService();

        service.SendNotification("A", "1", "First", EntityOperation.CREATE, "User");
        service.SendNotification("B", "2", "Second", EntityOperation.UPDATE, "User");
        service.SendNotification("C", "3", "Third", EntityOperation.DELETE, "User");

        var first = service.ReceiveNotification();
        var second = service.ReceiveNotification();
        var third = service.ReceiveNotification();

        Assert.Equal("A", first.EntityType);
        Assert.Equal("B", second.EntityType);
        Assert.Equal("C", third.EntityType);
    }

    [Fact]
    public void SendNotification_NullDisplayName_UsesIdFormat()
    {
        using var service = new NotificationService();

        service.SendNotification("Entity", "99", null, EntityOperation.CREATE, "User");

        var notification = service.ReceiveNotification();
        Assert.Contains("ID: 99", notification.Message);
    }

    [Fact]
    public void SendNotification_EmptyDisplayName_UsesIdFormat()
    {
        using var service = new NotificationService();

        service.SendNotification("Entity", "99", "", EntityOperation.CREATE, "User");

        var notification = service.ReceiveNotification();
        Assert.Contains("ID: 99", notification.Message);
    }
}

