using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Data;

public class SchoolContextTests
{
    [Fact]
    public void CanCreateDatabase()
    {
        using var context = TestHelper.CreateContext();

        Assert.True(context.Database.EnsureCreated());
    }

    [Fact]
    public void CanAddAndRetrieveStudent()
    {
        var dbName = Guid.NewGuid().ToString();
        using (var context = TestHelper.CreateContext(dbName))
        {
            context.Students.Add(new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 1, 1)
            });
            context.SaveChanges();
        }

        using (var context = TestHelper.CreateContext(dbName))
        {
            var student = context.Students.Single();
            Assert.Equal("Test", student.LastName);
            Assert.Equal("Student", student.FirstMidName);
        }
    }

    [Fact]
    public void CanAddAndRetrieveCourse()
    {
        var dbName = Guid.NewGuid().ToString();
        using (var context = TestHelper.CreateContext(dbName))
        {
            context.Departments.Add(new Department
            {
                DepartmentID = 1,
                Name = "Dept",
                Budget = 1000,
                StartDate = DateTime.Now
            });
            context.Courses.Add(new Course
            {
                CourseID = 100,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1
            });
            context.SaveChanges();
        }

        using (var context = TestHelper.CreateContext(dbName))
        {
            var course = context.Courses.Include(c => c.Department).Single();
            Assert.Equal("Test Course", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.NotNull(course.Department);
        }
    }

    [Fact]
    public void CanAddAndRetrieveDepartment()
    {
        var dbName = Guid.NewGuid().ToString();
        using (var context = TestHelper.CreateContext(dbName))
        {
            context.Departments.Add(new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 200000,
                StartDate = new DateTime(2020, 1, 1)
            });
            context.SaveChanges();
        }

        using (var context = TestHelper.CreateContext(dbName))
        {
            var dept = context.Departments.Single();
            Assert.Equal("Engineering", dept.Name);
            Assert.Equal(200000, dept.Budget);
        }
    }

    [Fact]
    public void CanAddAndRetrieveInstructor()
    {
        var dbName = Guid.NewGuid().ToString();
        using (var context = TestHelper.CreateContext(dbName))
        {
            context.Instructors.Add(new Instructor
            {
                LastName = "Prof",
                FirstMidName = "Test",
                HireDate = new DateTime(2015, 8, 1),
                CourseAssignments = new List<CourseAssignment>()
            });
            context.SaveChanges();
        }

        using (var context = TestHelper.CreateContext(dbName))
        {
            var instructor = context.Instructors.Single();
            Assert.Equal("Prof", instructor.LastName);
        }
    }

    [Fact]
    public void CourseAssignment_HasCompositeKey()
    {
        var dbName = Guid.NewGuid().ToString();
        using var context = TestHelper.CreateContext(dbName);

        context.Instructors.Add(new Instructor
        {
            ID = 1,
            LastName = "Inst",
            FirstMidName = "A",
            HireDate = DateTime.Now,
            CourseAssignments = new List<CourseAssignment>()
        });
        context.Departments.Add(new Department
        {
            DepartmentID = 1,
            Name = "D",
            Budget = 100,
            StartDate = DateTime.Now
        });
        context.Courses.Add(new Course
        {
            CourseID = 1,
            Title = "C",
            Credits = 1,
            DepartmentID = 1,
            CourseAssignments = new List<CourseAssignment>()
        });
        context.SaveChanges();

        context.CourseAssignments.Add(new CourseAssignment { InstructorID = 1, CourseID = 1 });
        context.SaveChanges();

        var ca = context.CourseAssignments.Single();
        Assert.Equal(1, ca.InstructorID);
        Assert.Equal(1, ca.CourseID);
    }

    [Fact]
    public void OfficeAssignment_IsOneToOneWithInstructor()
    {
        var dbName = Guid.NewGuid().ToString();
        using (var context = TestHelper.CreateContext(dbName))
        {
            context.Instructors.Add(new Instructor
            {
                ID = 1,
                LastName = "Office",
                FirstMidName = "Test",
                HireDate = DateTime.Now,
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Room 42" }
            });
            context.SaveChanges();
        }

        using (var context = TestHelper.CreateContext(dbName))
        {
            var instructor = context.Instructors.Include(i => i.OfficeAssignment).Single();
            Assert.NotNull(instructor.OfficeAssignment);
            Assert.Equal("Room 42", instructor.OfficeAssignment.Location);
        }
    }

    [Fact]
    public void Enrollment_RelationshipsWork()
    {
        var dbName = Guid.NewGuid().ToString();
        using (var context = TestHelper.CreateContext(dbName))
        {
            context.Departments.Add(new Department { DepartmentID = 1, Name = "D", Budget = 1, StartDate = DateTime.Now });
            context.Courses.Add(new Course { CourseID = 1, Title = "C", Credits = 1, DepartmentID = 1 });
            context.Students.Add(new Student { ID = 1, LastName = "S", FirstMidName = "T", EnrollmentDate = DateTime.Now });
            context.SaveChanges();
            context.Enrollments.Add(new Enrollment { CourseID = 1, StudentID = 1, Grade = Grade.A });
            context.SaveChanges();
        }

        using (var context = TestHelper.CreateContext(dbName))
        {
            var enrollment = context.Enrollments.Include(e => e.Course).Include(e => e.Student).Single();
            Assert.NotNull(enrollment.Course);
            Assert.NotNull(enrollment.Student);
            Assert.Equal(Grade.A, enrollment.Grade);
        }
    }

    [Fact]
    public void Person_FullName_ReturnsLastNameCommaFirst()
    {
        var student = new Student { LastName = "Doe", FirstMidName = "John" };

        Assert.Equal("Doe, John", student.FullName);
    }

    [Fact]
    public void Student_InheritsFromPerson()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Heir",
            EnrollmentDate = DateTime.Now
        };

        Assert.IsAssignableFrom<Person>(student);
    }

    [Fact]
    public void Instructor_InheritsFromPerson()
    {
        var instructor = new Instructor
        {
            LastName = "Test",
            FirstMidName = "Heir",
            HireDate = DateTime.Now
        };

        Assert.IsAssignableFrom<Person>(instructor);
    }
}

